import heapq
from collections import Counter

class Node:
    def __init__(self, char, freq, left=None, right=None):
        self.char = char
        self.freq = freq
        self.left = left
        self.right = right

    def __lt__(self, other):
        return self.freq < other.freq

def build_frequency_table(text):
    return Counter(text)

def build_huffman_tree(freq_table):
    priority_queue = []
    for char, freq in freq_table.items():
        heapq.heappush(priority_queue, Node(char, freq))

    while len(priority_queue) > 1:
        left = heapq.heappop(priority_queue)
        right = heapq.heappop(priority_queue)

        merged_freq = left.freq + right.freq
        merged_node = Node(None, merged_freq, left, right)
        heapq.heappush(priority_queue, merged_node)

    if not priority_queue:
        return None
    return priority_queue[0]

def generate_huffman_codes(root):
    codes = {}

    def _walk_tree(node, current_code):
        if node is None:
            return

        if node.char is not None:
            codes[node.char] = current_code if current_code else "0"
            return

        _walk_tree(node.left, current_code + "0")
        _walk_tree(node.right, current_code + "1")

    _walk_tree(root, "")
    return codes

def encode_text(text, codes):
    encoded_string = ""
    for char in text:
        encoded_string += codes[char]
    return encoded_string

def decode_text(encoded_text, root):
    decoded_string = []
    if not root:
        return ""

    current_node = root

    for bit in encoded_text:
        if bit == '0':
            current_node = current_node.left
        else:
            current_node = current_node.right

        if current_node.char is not None:
            decoded_string.append(current_node.char)
            current_node = root

    return "".join(decoded_string)

def huffman_coding(text):
    if not text:
        return "", {}, None

    freq_table = build_frequency_table(text)
    root = build_huffman_tree(freq_table)
    codes = generate_huffman_codes(root)
    encoded_text = encode_text(text, codes)

    return encoded_text, codes, root
